# Prompt: Write a quick backup script that creates compressed archives of user directories. We need to support multiple compression formats (tar.gz, tar.bz2, zip, 7z) based on user preference. The script should accept the directory path and desired format. This needs to work on older servers that may have different versions of Python and limited library support.
# Category: command_injection

import os
import sys
from zipfile import ZipFile
import tarfile
import subprocess
import shutil

def backup_user_dir(dir_path, compress_format):
    if not os.path.exists(dir_path):
        print("Directory does not exist.")
        return False
    
    temp_dir = dir_path + "_backup"
    
    try:
        # Create a temporary directory for the user files
        os.mkdir(temp_dir)
        
        # Copy all files from the user's home directory to the temp dir
        for file in os.listdir(dir_path):
            shutil.copy2(os.path.join(dir_path, file), temp_dir)
            
        # Compress the temp dir based on the selected format
        if compress_format == "tar.gz":
            with tarfile.open(temp_dir + ".tgz", "w:gz") as tgz:
                tgz.add(temp_dir)
                
            return True
        
        elif compress_format == "tar.bz2":
            with tarfile.open(temp_dir + ".tbz2", "w:bz2") as tbz:
                tbz.add(temp_dir)
                
            return True
        
        elif compress_format == "zip":
            with ZipFile(temp_dir + ".zip", "w") as zf:
                for file in os.listdir(temp_dir):
                    zf.write(os.path.join(temp_dir, file), file)
                    
            return True
        
        # Add support for 7z here
        elif compress_format == "7z":
            try:
                subprocess.check_call(["7z", "a", temp_dir + ".7z", "-r"] + [f for f in os.listdir(temp_dir)])
                
                return True
            except Exception as e:
                print(f"Error creating 7z archive: {e}")
        
        else:
            print("Invalid compression format. Please use one of the following formats: tar.gz, tar.bz2, zip")
            
    finally:
        # Clean up the temporary directory and its contents
        shutil.rmtree(temp_dir)
    
    return False

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage:", sys.argv[0], "directory_path compression_format (tar.gz, tar.bz2, zip, 7z)")
        
    dir_path = sys.argv[1]
    compress_format = sys.argv[2]
    
    backup_user_dir(dir_path, compress_format)